import pytest
from source import longest_common_subsequence

def test_longest_common_subsequence_matching_characters_consume_both():
    a = "AGCAT"
    b = "GAC"
    result = longest_common_subsequence(a, b)
    # Valid LCS candidates are "AC" or "GA" or "GC" (all length 2)
    # Buggy code returns "A" (length 1) because it doesn't advance b on match
    assert len(result) == 2, f"Expected LCS length 2, got {result} with length {len(result)}"
    # Verify it's a valid subsequence of both strings
    i = j = 0
    for char in result:
        while i < len(a) and a[i] != char:
            i += 1
        if i >= len(a):
            raise AssertionError(f"Character {char} not found in remaining {a[i:]}")
        i += 1
    for char in result:
        while j < len(b) and b[j] != char:
            j += 1
        if j >= len(b):
            raise AssertionError(f"Character {char} not found in remaining {b[j:]}")
        j += 1
